const solve = (points, target) => {
    // Helper function to serialize a point array into a string key
    const pointToString = (p) => `${p[0]},${p[1]},${p[2]}`;

    // Convert target to string for quick lookup
    const targetStr = pointToString(target);

    // 1. Initialize available points (Gen 0)
    let availablePoints = new Set();
    let pointsArray = []; // Store points as arrays for easier iteration

    for (const p of points) {
        const pStr = pointToString(p);
        if (!availablePoints.has(pStr)) {
            availablePoints.add(pStr);
            pointsArray.push(p);
        }
    }

    // 2. Check Gen 0
    if (availablePoints.has(targetStr)) {
        return 0;
    }

    // If we have fewer than 2 unique points, no new points can ever be generated.
    if (pointsArray.length < 2) {
        return -1;
    }

    let k = 1;

    // We loop indefinitely until the target is found or no new points are generated
    while (true) {
        let newlyGeneratedPoints = new Set();

        // Convert set back to array representation for indexed iteration
        // Note: Since the order doesn't strictly matter for generation, 
        // iterating over the current list of unique points is sufficient.
        const currentPointsList = Array.from(availablePoints).map(s => s.split(',').map(Number));
        const N = currentPointsList.length;

        let pointsWereGenerated = false;

        // Generate new points by pairing all distinct points from all previous generations
        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                const p1 = currentPointsList[i];
                const p2 = currentPointsList[j];

                // Calculate the midpoint (using floor)
                const cx = Math.floor((p1[0] + p2[0]) / 2);
                const cy = Math.floor((p1[1] + p2[1]) / 2);
                const cz = Math.floor((p1[2] + p2[2]) / 2);

                const newPoint = [cx, cy, cz];
                const newPointStr = pointToString(newPoint);

                // Only consider points that haven't been seen before
                if (!availablePoints.has(newPointStr)) {
                    newlyGeneratedPoints.add(newPointStr);
                    pointsWereGenerated = true;
                }
            }
        }

        // Check if the target was among the newly generated points
        if (newlyGeneratedPoints.has(targetStr)) {
            return k;
        }

        // If no new unique points were generated, we stop.
        if (!pointsWereGenerated) {
            return -1;
        }

        // Update the set of available points for the next generation
        newlyGeneratedPoints.forEach(pStr => availablePoints.add(pStr));

        k++;

        // Safety break, although constraints suggest this isn't necessary, 
        // coordinate space is small (0-6), so the number of reachable points is limited (7^3 = 343).
        if (k > 400) { 
             return -1;
        }
    }
};

