use std::collections::HashSet;

fn solve(points: Vec<Vec<i64>>, target: Vec<i64>) -> i64 {
    // Helper function to serialize a point array into a string key
    let point_to_string = |p: &[i64]| -> String {
        format!("{},{},{}", p[0], p[1], p[2])
    };

    // Convert target to string for quick lookup
    let target_str = point_to_string(&target);

    // 1. Initialize available points (Gen 0)
    // Store unique points represented as strings
    let mut available_points: HashSet<String> = HashSet::new();

    for p in points {
        let p_str = point_to_string(&p);
        available_points.insert(p_str);
    }

    // 2. Check Gen 0
    if available_points.contains(&target_str) {
        return 0;
    }

    // If we have fewer than 2 unique points, no new points can ever be generated.
    if available_points.len() < 2 {
        return -1;
    }

    let mut k: i64 = 1;

    // We loop until the target is found or no new points are generated
    while available_points.len() < 344 { // Safety limit based on max 7^3 points

        // Convert set back to a list of points (represented as Vec<[i64; 3]>) 
        // for indexed iteration needed for distinct pairs.
        let current_points_list: Vec<[i64; 3]> = available_points.iter()
            .map(|s| {
                let coords: Vec<i64> = s.split(',')
                    .filter_map(|part| part.parse().ok())
                    .collect();
                if coords.len() == 3 {
                    [coords[0], coords[1], coords[2]]
                } else {
                    // Should not happen given how points are generated/inserted
                    [0, 0, 0] 
                }
            })
            .collect();

        let n = current_points_list.len();

        if n < 2 {
            // Should have been caught earlier, but safeguard
            return -1;
        }

        let mut newly_generated_points: HashSet<String> = HashSet::new();
        let mut points_were_generated = false;

        // Generate new points by pairing all distinct points from the current set
        for i in 0..n {
            for j in (i + 1)..n {
                let p1 = current_points_list[i];
                let p2 = current_points_list[j];

                // Calculate the midpoint (using floor division)
                let cx = (p1[0] + p2[0]) / 2;
                let cy = (p1[1] + p2[1]) / 2;
                let cz = (p1[2] + p2[2]) / 2;

                let new_point: [i64; 3] = [cx, cy, cz];
                let new_point_str = point_to_string(&new_point);

                // Only consider points that haven't been seen before
                if !available_points.contains(&new_point_str) {
                    newly_generated_points.insert(new_point_str);
                    points_were_generated = true;
                }
            }
        }

        // Check if the target was among the newly generated points
        if newly_generated_points.contains(&target_str) {
            return k;
        }

        // If no new unique points were generated, we stop.
        if !points_were_generated {
            return -1;
        }

        // Update the set of available points for the next generation
        for p_str in newly_generated_points {
            available_points.insert(p_str);
        }

        k += 1;
    }

    // If the loop exits due to hitting the arbitrary safety limit (max points reached)
    -1
}

