fn solve(points: Vec<Vec<i64>>, target: Vec<i64>) -> i64 {
    // Since coordinates are 0 <= coord <= 6, we use base 7 encoding for efficient set tracking.
    const BASE: i64 = 7;
    const MAX_INDEX: usize = 7 * 7 * 7;

    // Helper function to convert a point [x, y, z] to a unique integer index (0 to 342)
    let point_to_index = |p: &[i64]| -> usize {
        // p[0]*7^2 + p[1]*7^1 + p[2]*7^0
        (p[0] * 49 + p[1] * 7 + p[2]) as usize
    };

    // Helper function to check if two points are equal
    let points_equal = |p1: &[i64], p2: &[i64]| -> bool {
        p1[0] == p2[0] && p1[1] == p2[1] && p1[2] == p2[2]
    };

    // available[i] tracks if the point corresponding to index i has been generated/is initial.
    let mut available = vec![false; MAX_INDEX];
    // P_list stores the actual coordinate vectors of all unique points found so far.
    let mut p_list: Vec<Vec<i64>> = Vec::new();

    // --- Generation 0 Check ---
    let mut initial_target_found = false;
    for p_in in points {
        let p_ref: &[i64] = &p_in;
        let index = point_to_index(p_ref);

        if !available[index] {
            available[index] = true;
            p_list.push(p_in.clone());

            if points_equal(p_ref, &target) {
                initial_target_found = true;
            }
        }
    }

    if initial_target_found {
        return 0;
    }

    // If we have fewer than 2 unique points, no new points can ever be generated.
    if p_list.len() < 2 {
        return -1;
    }

    let mut k: i64 = 1;

    // --- Iterative Generations (k >= 1) ---
    loop {
        let N = p_list.len();
        let mut newly_generated_points: Vec<Vec<i64>> = Vec::new();
        let mut target_found_in_k = false;

        // Iterate over all distinct pairs in the current pool (P_list)
        for i in 0..N {
